const day2Pilot = day2.filter((lessonItem) => ![
  'art810-d02-09-underwater-musician',
  'art810-d02-11-two-friends',
].includes(lessonItem.slug));

const artPilotRefinements = {




  // BEGIN art810 day2 art pass A





  // END art810 day2 art pass A
  // BEGIN art810 day2 art pass B





  // END art810 day2 art pass B
};
function refineArtPilotLesson(lessonItem) {
  const changes = artPilotRefinements[lessonItem.slug];
  return changes ? { ...lessonItem, ...changes } : lessonItem;
}

export const eightTenArtPilotLessons = [...day1, ...day2Pilot].map(refineArtPilotLesson);

